        # Check if cells are correlated (not independent)
        h1 = eng.cells[0].hidden.squeeze().detach()
        h2 = eng.cells[1].hidden.squeeze().detach()
        corr = F.cosine_similarity(h1.unsqueeze(0), h2.unsqueeze(0)).item()
