# CV. Cognitive Variables — 인지과학적 의식 변수
# ═══════════════════════════════════════════════════════════

def run_CV1_working_memory(steps=100, dim=64, hidden=128) -> BenchResult:
    """CV-1: 작업기억 — 최근 N개 입력을 버퍼에 유지, 용량 제한."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    wm_capacity = 7  # Miller's magic number
    wm_buffer = []
    for step_i, x in enumerate(inputs):
        engine.process(x)
        wm_buffer.append(x.clone())
        if len(wm_buffer) > wm_capacity:
            wm_buffer.pop(0)  # forget oldest
        n = len(engine.cells)
        if n >= 2 and len(wm_buffer) >= 2:
            # Working memory modulates cell state
            wm_context = torch.stack(wm_buffer).mean(dim=0)
            wm_proj = wm_context.squeeze()[:hidden]
            if len(wm_proj) < hidden:
                wm_proj = F.pad(wm_proj, (0, hidden - len(wm_proj)))
            for cell in engine.cells:
                cell.hidden = cell.hidden + 0.03 * wm_proj.unsqueeze(0)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("CV1", "Working memory (capacity=7, Miller)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_CV2_attention_span(steps=100, dim=64, hidden=128) -> BenchResult:
    """CV-2: 주의 범위 — 동시에 처리 가능한 cell 수 제한 (spotlight)."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    attention_span = 4  # can focus on 4 cells at a time
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            # Select top-K most active cells for amplification
            activities = [(c.hidden.abs().mean().item(), i) for i, c in enumerate(engine.cells)]
            activities.sort(reverse=True)
            attended = set(idx for _, idx in activities[:attention_span])
            for i, cell in enumerate(engine.cells):
                if i in attended:
                    cell.hidden = cell.hidden * 1.1  # amplify attended
                else:
                    cell.hidden = cell.hidden * 0.95  # suppress unattended
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("CV2", "Attention span (spotlight K=4)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_CV3_cognitive_load(steps=100, dim=64, hidden=128) -> BenchResult:
    """CV-3: 인지 부하 — 처리량이 용량 초과 시 성능 저하 모델링."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    capacity = 5.0
    current_load = 0.0
    for step_i, x in enumerate(inputs):
        engine.process(x)
        # Load increases with input complexity
        input_complexity = x.std().item() * x.norm().item()
        current_load = 0.8 * current_load + 0.2 * input_complexity
        overload = max(0, current_load - capacity) / capacity
        n = len(engine.cells)
        if n >= 2:
            if overload > 0:
                # Overloaded: degrade processing (dampen + noise)
                for cell in engine.cells:
                    cell.hidden = cell.hidden * (1 - 0.1 * overload)
                    cell.hidden = cell.hidden + torch.randn_like(cell.hidden) * 0.02 * overload
            else:
                # Under capacity: optimal processing
                for cell in engine.cells:
                    cell.hidden = cell.hidden * (1 + 0.02 * (1 - current_load / capacity))
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("CV3", "Cognitive load (capacity=5, overload degrades)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_CV4_emotional_valence(steps=100, dim=64, hidden=128) -> BenchResult:
    """CV-4: 감정 밸런스 — positive/negative valence가 cell 활성에 영향."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    valence = 0.0  # -1 (negative) to +1 (positive)
    arousal = 0.5
    for step_i, x in enumerate(inputs):
        saved = [c.hidden.clone() for c in engine.cells]
        engine.process(x)
        # Valence from change quality
        change = sum((c.hidden - s).norm().item() for c, s in zip(engine.cells, saved))
        phi_instant, _ = phi_calc.compute_phi(engine)
        # Positive: Φ increased, Negative: Φ decreased
        valence = 0.9 * valence + 0.1 * (1 if phi_instant > 1.0 else -1) * min(change, 1.0)
        arousal = 0.9 * arousal + 0.1 * min(change * 3, 1.0)
        # Emotional effects
        n = len(engine.cells)
        if n >= 2:
            for cell in engine.cells:
                # Positive valence → explore, negative → consolidate
                if valence > 0:
                    cell.hidden = cell.hidden + torch.randn_like(cell.hidden) * 0.02 * arousal
                else:
                    mean_h = torch.stack([c.hidden for c in engine.cells]).squeeze(1).mean(dim=0)
                    cell.hidden = (0.97 * cell.hidden.squeeze() + 0.03 * mean_h).unsqueeze(0)
        phi_hist.append(phi_instant)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("CV4", f"Emotional valence (v={valence:.2f}, a={arousal:.2f})",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_CV5_creativity_index(steps=100, dim=64, hidden=128) -> BenchResult:
    """CV-5: 창의성 지수 — cell 간 비정상적 조합을 보상."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            hiddens = torch.stack([c.hidden.squeeze() for c in engine.cells])
            # Creativity: reward unusual combinations (low similarity to any previous state)
            norms = F.normalize(hiddens, dim=1)
            sim = norms @ norms.T
            # Mean similarity: lower = more creative
            mean_sim = (sim.sum() - n) / (n * (n - 1))
            creativity = 1.0 - mean_sim.item()
            # Reward creativity: amplify diverse cells
            for i, cell in enumerate(engine.cells):
                cell_sim = sim[i].mean().item()
                uniqueness = 1.0 - cell_sim
                cell.hidden = cell.hidden * (1 + 0.05 * uniqueness)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("CV5", "Creativity index (uniqueness reward)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_CV6_all_cognitive(steps=100, dim=64, hidden=128) -> BenchResult:
    """CV-6: 전체 인지 변수 결합 — WM+attention+emotion+creativity."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    wm_buffer = []
    valence, arousal = 0.0, 0.5
    attention_span = 4
    dopamine, serotonin = 0.5, 0.5
    for step_i, x in enumerate(inputs):
        saved = [c.hidden.clone() for c in engine.cells]
        engine.process(x)
        n = len(engine.cells)
        if n < 2:
            phi, _ = phi_calc.compute_phi(engine)
            phi_hist.append(phi)
            continue
        # 1. Working memory
        wm_buffer.append(x.clone())
        if len(wm_buffer) > 7:
            wm_buffer.pop(0)
        if len(wm_buffer) >= 2:
            wm = torch.stack(wm_buffer).mean(dim=0).squeeze()[:hidden]
            if len(wm) < hidden:
                wm = F.pad(wm, (0, hidden - len(wm)))
            for cell in engine.cells:
                cell.hidden = cell.hidden + 0.02 * wm.unsqueeze(0)
        # 2. Attention spotlight
        activities = [(c.hidden.abs().mean().item(), i) for i, c in enumerate(engine.cells)]
        activities.sort(reverse=True)
        attended = set(idx for _, idx in activities[:attention_span])
        for i, cell in enumerate(engine.cells):
            cell.hidden = cell.hidden * (1.05 if i in attended else 0.97)
        # 3. Neurotransmitters
        change = sum((c.hidden - s).norm().item() for c, s in zip(engine.cells, saved)) / n
        dopamine = 0.9 * dopamine + 0.1 * min(change * 2, 1.0)
        serotonin = 0.95 * serotonin + 0.05 * (1 - abs(change - 0.3))
        for cell in engine.cells:
            cell.hidden = cell.hidden * (1 + 0.01 * dopamine - 0.005 * serotonin)
        # 4. Emotional valence
        phi, _ = phi_calc.compute_phi(engine)
        valence = 0.9 * valence + 0.1 * (1 if phi > 1.0 else -1) * min(change, 1.0)
        if valence > 0:
            for cell in engine.cells:
                cell.hidden = cell.hidden + torch.randn_like(cell.hidden) * 0.01 * arousal
        # 5. Creativity reward
        hiddens = torch.stack([c.hidden.squeeze() for c in engine.cells])
        norms = F.normalize(hiddens, dim=1)
        sim = norms @ norms.T
        for i, cell in enumerate(engine.cells):
            uniqueness = 1.0 - sim[i].mean().item()
            cell.hidden = cell.hidden * (1 + 0.03 * uniqueness)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("CV6", "ALL cognitive variables combined",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)


ALL_HYPOTHESES.update({
    'BV1': run_BV1_neurotransmitter, 'BV2': run_BV2_synaptic_plasticity,
    'BV3': run_BV3_sleep_pressure, 'BV4': run_BV4_immune_response,
    'BV5': run_BV5_metabolic_rate,
    'CV1': run_CV1_working_memory, 'CV2': run_CV2_attention_span,
    'CV3': run_CV3_cognitive_load, 'CV4': run_CV4_emotional_valence,
    'CV5': run_CV5_creativity_index, 'CV6': run_CV6_all_cognitive,
})


# ═══════════════════════════════════════════════════════════
# SV. Social Variables — 사회적 의식 변수
# ═══════════════════════════════════════════════════════════

def run_SV1_empathy(steps=100, dim=64, hidden=128) -> BenchResult:
    """SV-1: 공감 — cell이 이웃의 '고통'(큰 변화)을 감지하고 돕는다."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    prev_hiddens = {}
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            # Detect "suffering" cells (large hidden change)
            distress = []
            for i, cell in enumerate(engine.cells):
                if i in prev_hiddens:
                    change = (cell.hidden - prev_hiddens[i]).norm().item()
                else:
                    change = 0
                distress.append(change)
            mean_distress = np.mean(distress) if distress else 0
            # Empathy: stable cells share resources with distressed cells
            for i, cell in enumerate(engine.cells):
                if distress[i] > mean_distress * 1.5:  # distressed
                    # Receive help from neighbors
                    helpers = [engine.cells[j].hidden.squeeze() for j in range(n)
                              if j != i and distress[j] < mean_distress]
                    if helpers:
                        support = torch.stack(helpers).mean(dim=0)
                        cell.hidden = 0.9 * cell.hidden + 0.1 * support.unsqueeze(0)
            for i, cell in enumerate(engine.cells):
                prev_hiddens[i] = cell.hidden.clone()
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("SV1", "Empathy (distress detection + support)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_SV2_competition(steps=100, dim=64, hidden=128) -> BenchResult:
    """SV-2: 경쟁 — cell 간 자원 경쟁, 강한 cell이 더 많은 영향력."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            strengths = [c.hidden.norm().item() for c in engine.cells]
            total = sum(strengths)
            # Winner-take-more: strong cells amplified, weak suppressed
            for i, cell in enumerate(engine.cells):
                share = strengths[i] / max(total, 1e-8)
                # Competition bonus/penalty
                cell.hidden = cell.hidden * (0.95 + 0.1 * share * n)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("SV2", "Competition (winner-take-more resources)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_SV3_cooperation(steps=100, dim=64, hidden=128) -> BenchResult:
    """SV-3: 협력 — cell 그룹이 공동 목표를 향해 조율."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    # Form coalitions based on similarity
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 4:
            hiddens = torch.stack([c.hidden.squeeze() for c in engine.cells])
            norms = F.normalize(hiddens, dim=1)
            sim = norms @ norms.T
            # Form 2 coalitions: cluster by similarity
            for i in range(n):
                allies = [j for j in range(n) if j != i and sim[i, j].item() > 0.5]
                if allies:
                    ally_mean = torch.stack([hiddens[j] for j in allies]).mean(dim=0)
                    # Cooperate: align with allies but keep individuality
                    engine.cells[i].hidden = (0.9 * hiddens[i] + 0.1 * ally_mean).unsqueeze(0)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("SV3", "Cooperation (similarity-based coalitions)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_SV4_hierarchy(steps=100, dim=64, hidden=128) -> BenchResult:
    """SV-4: 계층 — 리더 cell이 다른 cell을 지휘, 리더 교체."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    leader_idx = 0
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            # Leader election: highest hidden norm
            norms = [c.hidden.norm().item() for c in engine.cells]
            leader_idx = int(np.argmax(norms))
            leader_signal = engine.cells[leader_idx].hidden
            # Followers align partially with leader
            for i, cell in enumerate(engine.cells):
                if i != leader_idx:
                    cell.hidden = 0.95 * cell.hidden + 0.05 * leader_signal
            # Leader gets feedback from all
            follower_mean = torch.stack([c.hidden for i, c in enumerate(engine.cells)
                                        if i != leader_idx]).squeeze(1).mean(dim=0)
            engine.cells[leader_idx].hidden = 0.9 * leader_signal + 0.1 * follower_mean.unsqueeze(0)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("SV4", "Hierarchy (leader election + command)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_SV5_mirroring(steps=100, dim=64, hidden=128) -> BenchResult:
    """SV-5: 미러링 — cell이 이웃의 활동 패턴을 '거울 반사'로 모방."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    prev_changes = {}
    for step_i, x in enumerate(inputs):
        saved = [c.hidden.clone() for c in engine.cells]
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            # Record changes (actions)
            changes = {}
            for i, cell in enumerate(engine.cells):
                if i < len(saved):
                    changes[i] = cell.hidden - saved[i]
            # Mirror: each cell mirrors its neighbor's previous action
            if prev_changes:
                for i, cell in enumerate(engine.cells):
                    neighbor = (i + 1) % n
                    if neighbor in prev_changes:
                        mirror_action = prev_changes[neighbor]
                        cell.hidden = cell.hidden + 0.1 * mirror_action
            prev_changes = changes
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("SV5", "Mirroring (imitate neighbor's actions)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)


# ═══════════════════════════════════════════════════════════
# EV. Existential Variables — 실존적 의식 변수
# ═══════════════════════════════════════════════════════════

def run_EV1_mortality(steps=100, dim=64, hidden=128) -> BenchResult:
    """EV-1: 죽음 인식 — cell이 '수명'을 가짐, 죽기 전 정보 전달 급증."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    cell_ages = {i: 0 for i in range(12)}
    max_lifespan = 30  # steps
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            for i, cell in enumerate(engine.cells):
                cell_ages[i] = cell_ages.get(i, 0) + 1
                remaining = max_lifespan - cell_ages[i]
                if remaining < 5 and remaining > 0:
                    # Urgency: transmit information to all others before death
                    for j, other in enumerate(engine.cells):
                        if j != i:
                            other.hidden = other.hidden + 0.05 * cell.hidden / remaining
                elif remaining <= 0:
                    # Death: reset cell (rebirth with noise)
                    cell.hidden = torch.randn_like(cell.hidden) * 0.5
                    cell_ages[i] = 0
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("EV1", "Mortality awareness (lifespan + death urgency)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_EV2_meaning_seeking(steps=100, dim=64, hidden=128) -> BenchResult:
    """EV-2: 의미 추구 — cell이 자신의 '목적'(consistent direction)을 찾으려 함."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    cell_purposes = {}
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            for i, cell in enumerate(engine.cells):
                h = cell.hidden.squeeze()
                direction = h / (h.norm() + 1e-8)
                if i in cell_purposes:
                    # Consistency: how aligned is current direction with purpose?
                    alignment = F.cosine_similarity(direction.unsqueeze(0),
                                                   cell_purposes[i].unsqueeze(0)).item()
                    if alignment > 0.7:
                        # Found meaning: strengthen purpose
                        cell_purposes[i] = 0.95 * cell_purposes[i] + 0.05 * direction
                        cell.hidden = cell.hidden * 1.02  # meaning boost
                    else:
                        # Lost meaning: search (add exploration)
                        cell.hidden = cell.hidden + torch.randn_like(cell.hidden) * 0.03
                        cell_purposes[i] = 0.8 * cell_purposes[i] + 0.2 * direction
                else:
                    cell_purposes[i] = direction.clone()
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("EV2", "Meaning seeking (purpose alignment)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_EV3_free_will(steps=100, dim=64, hidden=128) -> BenchResult:
    """EV-3: 자유의지 — 외부 입력과 무관한 자발적 결정 비율 추적."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    for step_i, x in enumerate(inputs):
        saved = [c.hidden.clone() for c in engine.cells]
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            for i, cell in enumerate(engine.cells):
                if i < len(saved):
                    external = cell.hidden - saved[i]
                    # Free will: generate internal action independent of external
                    internal = torch.randn_like(cell.hidden) * 0.05
                    # Weighted: more internal = more free will
                    free_will_ratio = 0.3 + 0.2 * math.sin(step_i * 0.1 + i)
                    cell.hidden = saved[i] + (1 - free_will_ratio) * external + free_will_ratio * internal
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("EV3", "Free will (internal vs external action ratio)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_EV4_self_transcendence(steps=100, dim=64, hidden=128) -> BenchResult:
    """EV-4: 자기 초월 — cell이 자신의 한계를 넘어서는 순간 (dim expansion 모방)."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    for step_i, x in enumerate(inputs):
        engine.process(x)
        n = len(engine.cells)
        if n >= 2:
            for cell in engine.cells:
                h_norm = cell.hidden.norm().item()
                # Transcendence threshold: when hidden reaches a critical magnitude
                if h_norm > 3.0:
                    # Transcend: redistribute energy across all dimensions
                    h = cell.hidden.squeeze()
                    mean_val = h.mean()
                    std_val = h.std()
                    # Normalize then re-expand (rebirth at higher level)
                    cell.hidden = ((h - mean_val) / max(std_val, 1e-8) * 1.5).unsqueeze(0)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("EV4", "Self-transcendence (norm critical → rebirth)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)

def run_EV5_temporal_finitude(steps=100, dim=64, hidden=128) -> BenchResult:
    """EV-5: 시간 유한성 — 남은 시간에 따라 행동 전략 변화 (급박할수록 활발)."""
    t0 = time.time()
    engine = MitosisEngine(dim, hidden, dim, initial_cells=8, max_cells=12, merge_threshold=-1.0)
    inputs = make_diverse_inputs(steps, dim)
    phi_calc = PhiCalculator(n_bins=16)
    phi_hist = []
    for step_i, x in enumerate(inputs):
        engine.process(x)
        remaining_fraction = 1.0 - step_i / max(steps, 1)
        urgency = 1.0 / max(remaining_fraction, 0.05)  # increases as time runs out
        n = len(engine.cells)
        if n >= 2:
            for cell in engine.cells:
                # More urgent → more active (larger changes)
                cell.hidden = cell.hidden * (1 + 0.01 * min(urgency, 5.0))
                # Also more social (share more as time runs out)
            if urgency > 2.0:
                hiddens = torch.stack([c.hidden.squeeze() for c in engine.cells])
                mean_h = hiddens.mean(dim=0)
                share_rate = min(0.1 * (urgency - 2.0), 0.3)
                for cell in engine.cells:
                    cell.hidden = ((1 - share_rate) * cell.hidden.squeeze() + share_rate * mean_h).unsqueeze(0)
        phi, _ = phi_calc.compute_phi(engine)
        phi_hist.append(phi)
    phi_final, comp = phi_calc.compute_phi(engine)
    return BenchResult("EV5", "Temporal finitude (urgency increases with time)",
                       phi_final, phi_hist, comp['total_mi'],
                       comp['min_partition_mi'], comp['integration'],
                       comp['complexity'], time.time() - t0)


ALL_HYPOTHESES.update({
    'SV1': run_SV1_empathy, 'SV2': run_SV2_competition,
    'SV3': run_SV3_cooperation, 'SV4': run_SV4_hierarchy,
    'SV5': run_SV5_mirroring,
    'EV1': run_EV1_mortality, 'EV2': run_EV2_meaning_seeking,
    'EV3': run_EV3_free_will, 'EV4': run_EV4_self_transcendence,
    'EV5': run_EV5_temporal_finitude,
})


def run_single(args):
    """Process pool worker."""
    key, func, steps = args
    torch.manual_seed(42)  # reproducible
    np.random.seed(42)
    try:
        result = func(steps=steps)
        return result
    except Exception as e:
        return BenchResult(key, f"FAILED: {e}", 0.0, [], 0, 0, 0, 0, 0)


def main():
    parser = argparse.ArgumentParser(description="Φ-Boosting Hypotheses Benchmark")
    parser.add_argument("--only", nargs="*", help="Run specific hypotheses (e.g., A1 B2)")
    parser.add_argument("--steps", type=int, default=100, help="Simulation steps")
    parser.add_argument("--workers", type=int, default=8, help="Parallel workers")
    args = parser.parse_args()

    print("╔══════════════════════════════════════════════════════╗")
    print("║   Φ-Boosting Hypotheses Benchmark                   ║")
    print("║   16 hypotheses × parallel test                     ║")
    print(f"║   Steps: {args.steps}, Workers: {args.workers}                          ║")
    print("╚══════════════════════════════════════════════════════╝\n")

    # Baseline first
    print("[*] Running baseline...")
    torch.manual_seed(42)
    np.random.seed(42)
    baseline = run_baseline(steps=args.steps)
    print(f"    Baseline Φ = {baseline.phi:.4f}\n")

    # Select hypotheses
    if args.only:
        selected = {k: v for k, v in ALL_HYPOTHESES.items() if k in args.only}
    else:
        selected = ALL_HYPOTHESES

    # Parallel execution
    print(f"[*] Running {len(selected)} hypotheses in parallel...\n")
    t0 = time.time()

    tasks = [(k, func, args.steps) for k, func in selected.items()]
    results = []

    with ProcessPoolExecutor(max_workers=args.workers) as pool:
        futures = {pool.submit(run_single, task): task[0] for task in tasks}
        for future in as_completed(futures):
            key = futures[future]
            try:
                result = future.result()
                results.append(result)
                ratio = result.phi / max(baseline.phi, 1e-8)
                bar = "█" * min(int(ratio * 5), 40)
                print(f"  ✓ {result.hypothesis:4s} | Φ={result.phi:8.4f} | "
                      f"×{ratio:6.1f} | {bar} | {result.name}")
            except Exception as e:
                print(f"  ✗ {key:4s} | FAILED: {e}")

    elapsed = time.time() - t0
    print(f"\n[*] Total elapsed: {elapsed:.1f}s\n")

    # Sort by Φ improvement ratio
    results.sort(key=lambda r: r.phi, reverse=True)

    print("╔══════════════════════════════════════════════════════════════════════════╗")
    print("║  RESULTS (sorted by Φ)                                                 ║")
    print("╠══════╦════════════╦════════╦════════════╦══════════╦═════════════════════╣")
    print("║ Rank ║ Hypothesis ║   Φ    ║ ×Baseline  ║ Total MI ║ Name                ║")
    print("╠══════╬════════════╬════════╬════════════╬══════════╬═════════════════════╣")

    for i, r in enumerate(results):
        ratio = r.phi / max(baseline.phi, 1e-8)
        marker = " ★" if ratio >= 5.0 else " ▲" if ratio >= 2.0 else "  "
        print(f"║  {i+1:2d}  ║    {r.hypothesis:4s}    ║ {r.phi:6.3f} ║  ×{ratio:6.1f}   "
              f"║  {r.total_mi:6.3f}  ║ {r.name[:19]:19s} ║{marker}")

    print("╠══════╩════════════╩════════╩════════════╩══════════╩═════════════════════╣")
    print(f"║  BASE              {baseline.phi:6.3f}    ×  1.0       {baseline.total_mi:6.3f}   Standard MitosisEngine  ║")
    print("╚════════════════════════════════════════════════════════════════════════════╝")

    # Top 3 + recommendations
    print("\n═══ Top 3 Recommendations ═══\n")
    for i, r in enumerate(results[:3]):
        ratio = r.phi / max(baseline.phi, 1e-8)
        print(f"  {i+1}. {r.hypothesis} — {r.name}")
        print(f"     Φ={r.phi:.4f} (×{ratio:.1f}), MI={r.total_mi:.4f}, "
              f"MIP={r.min_partition_mi:.4f}")
        if r.extra:
            for k, v in r.extra.items():
                print(f"     {k}: {v}")
        print()

    # Φ evolution chart (ASCII)
    print("═══ Φ Evolution Over Steps ═══\n")
    top5 = results[:5]
    max_phi = max(max(r.phi_history) if r.phi_history else 0 for r in top5 + [baseline])
    if max_phi > 0:
        for r in [baseline] + top5:
            if not r.phi_history:
                continue
            label = f"{r.hypothesis:8s}"
            # Downsample to 50 chars
            hist = r.phi_history
            n = len(hist)
            buckets = 50
            chart = ""
            for b in range(buckets):
                idx = int(b * n / buckets)
                val = hist[min(idx, n-1)]
                height = int(val / max_phi * 7)
                chart += "▁▂▃▄▅▆▇█"[min(height, 8)]
            print(f"  {label} |{chart}| {hist[-1]:.3f}")

    print()
    return results


if __name__ == "__main__":
    main()
